import numpy as np
from rank_bm25 import BM25Okapi

def _bm25_tokenize(text):
    import re
    return re.findall(r'\b\w\w+\b', text.lower())

def search(query, df, bm25, model, index, top_k=10):
    query_tokens = _bm25_tokenize(query)
    bm25_scores = bm25.get_scores(query_tokens)

    query_vec = model.encode([query]).astype("float32")
    dists, idxs = index.search(query_vec, 1000)

    # RRF params
    k_rrf = 60
    ranks = np.zeros(len(df))

    # BM25 contribution
    sorted_bm25 = np.argsort(bm25_scores)[::-1]
    for r, idx in enumerate(sorted_bm25[:500]):
        ranks[idx] += 1.0 / (k_rrf + r)

    # Semantic contribution
    for r, idx in enumerate(idxs[0][:500]):
        ranks[idx] += 1.0 / (k_rrf + r)

    # Title match boost: if query words in title, boost significantly
    query_lower = query.lower()
    for i, title in enumerate(df['title']):
        if query_lower in title.lower() or title.lower() in query_lower:
            ranks[i] += 0.5

    # Genre boost: simple overlap
    query_genres = [g.strip().lower() for g in query.split() if g.lower() in ['action', 'comedy', 'drama', 'horror', 'sci-fi', 'romance', 'thriller']]
    if query_genres:
        for i, genres in enumerate(df['genres']):
            if any(g in genres.lower() for g in query_genres):
                ranks[i] += 0.2

    # Final selection
    top_indices = np.argsort(ranks)[-top_k:][::-1]
    return df.iloc[top_indices].to_dict("records")

import numpy as np
from rank_bm25 import BM25Okapi

def _bm25_tokenize(text):
    import re
    return re.findall(r'\b\w\w+\b', text.lower())

def search(query, df, bm25, model, index, top_k=10):
    tokens = _bm25_tokenize(query)
    query_vec = model.encode([query]).astype("float32")

    # Retrieval
    bm25_scores = bm25.get_scores(tokens)
    top_bm25_idx = np.argpartition(bm25_scores, -100)[-100:]

    dists, idxs = index.search(query_vec, 100)
    idxs = idxs[0]
    dists = dists[0]

    # Unique Candidates
    candidates = np.unique(np.concatenate([top_bm25_idx, idxs]))

    # RRF scoring
    rrf_scores = np.zeros(len(candidates))

    # BM25 RRF
    bm25_map = {idx: i for i, idx in enumerate(np.argsort(bm25_scores[candidates])[::-1])}
    for i, c_idx in enumerate(candidates):
        if c_idx in bm25_map:
            rrf_scores[i] += 1.0 / (60 + bm25_map[c_idx])

    # Semantic RRF
    sem_map = {idx: i for i, idx in enumerate(idxs)}
    for i, c_idx in enumerate(candidates):
        if c_idx in sem_map:
            rrf_scores[i] += 1.0 / (60 + sem_map[c_idx])

    # Genre Boosting
    target_genres = [t for t in tokens if t in ["drama", "comedy", "thriller", "action", "sci-fi", "horror", "romance", "documentary"]]
    if target_genres:
        for i, c_idx in enumerate(candidates):
            g = str(df.iloc[c_idx]['genres']).lower()
            if any(tg in g for tg in target_genres):
                rrf_scores[i] *= 1.2

    # Popularity Boost
    pop = np.log1p(df.iloc[candidates]['vote_count'])
    rrf_scores += (pop / pop.max()) * 0.05

    # Result sorting
    best_idx = candidates[np.argsort(rrf_scores)[::-1][:top_k]]
    return df.iloc[best_idx].to_dict("records")
